-- Enrichment marathon batch: XWiki, Yaak, Yakforms, yarn.social, Yepic AI, Yeti-Switch, YetiForce, Yext

-- ── XWiki ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source enterprise wiki and structured-content platform that lets teams document, organize, and build lightweight applications on top of a shared knowledge base.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free self-hosted Community edition; paid support and cloud plans start at roughly 2 euros per user per month, billed annually$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$50-100 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$XWiki Review: Open-Source Wiki and App Platform, Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See what XWiki offers: a free, open-source enterprise wiki for documentation and knowledge management, plus its app-building tools, pricing tiers, and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$XWiki is an open-source enterprise wiki and structured-content platform originally released in January 2004 by Ludovic Dubost, who founded the company behind it, now known as XWiki SAS, headquartered in Paris, France with a development team also based in Iasi, Romania. Unlike simple documentation wikis, XWiki combines page-based collaborative editing with an application-development layer, letting technical and semi-technical users build structured data forms, workflows, and small internal apps directly on top of wiki pages using XWiki's scripting and macro system. Core capabilities include WYSIWYG and wiki-syntax editing, OpenDocument-based import and export, page annotations and tagging, granular rights and permissions management, full version history, and support for running many interlinked wikis as a wiki farm. XWiki is licensed under LGPL and can be self-hosted for free with no user limits, which makes it popular with government agencies, universities, and privacy-conscious organizations that want to avoid vendor lock-in on their knowledge base. XWiki SAS, the commercial entity behind the project, sells paid support subscriptions and managed cloud hosting on top of the free core. These commercial tiers are Starter (cloud only, up to 25 users), Basic (cloud or on-premise, up to 1,000 users), Business (cloud or on-premise, up to 10,000 users, includes OIDC and SAML single sign-on and Confluence or SharePoint migration tooling), and Enterprise (unlimited users, advanced deployment options including Kubernetes, dedicated account management). All paid tiers add early security patches, premium extensions, and an antivirus application not available in the free Community edition. XWiki also offers consulting and training services billed per day, and provides a 50 percent discount on support along with free Starter-tier cloud hosting for qualifying open-source projects and NGOs. The platform is extensible through a large marketplace of community-built extensions and applications, and exposes a RESTful API for integrating with external systems. Its main audience is IT departments, knowledge management teams, and software organizations that need an enterprise-grade, self-hostable alternative to Confluence, SharePoint, or MediaWiki, especially where data residency, customization depth, or the ability to build lightweight internal apps without a separate low-code platform matter more than a slick modern interface.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fb6f9f95-9f4c-4661-825d-e8c01f5894f4';

