-- ── Yaak ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Local-first desktop API client for testing REST, GraphQL, gRPC, WebSocket, and SSE requests, built as a privacy-focused alternative to Postman and Insomnia.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for personal use; commercial license from $79 per year per individual$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Yaak Review: Local-First API Client, Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Yaak, a local-first desktop API client for REST, GraphQL, gRPC, WebSocket, and SSE testing, plus its features, open-source license, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yaak is a desktop API client used to build, send, and debug HTTP, GraphQL, gRPC, WebSocket, and Server-Sent Events requests. It was launched in January 2024 by Mountain Loop Labs, a company founded by the same developer who previously created and sold the popular API client Insomnia. Yaak was built as a response to what its creator described as existing API tools changing for the worse after acquisition, positioning it as a developer-first, privacy-respecting alternative to Postman and Insomnia. The defining characteristic of Yaak is its local-first architecture: requests, collections, and configuration are stored as plain text files on the user's machine rather than in a cloud account, and the application works fully offline without requiring sign-up or an internet connection. This design also makes Yaak naturally compatible with Git, since collections can be versioned and shared through a normal Git repository rather than a proprietary sync service. Sensitive values such as API keys and tokens can be stored using ChaCha20-Poly1305 encryption for local secrets management. Beyond core request building, Yaak supports request chaining and dynamic templating with variables, multiple windows for working on several projects simultaneously, over 30 customizable UI themes, and a CLI plus agent-oriented tooling for scripting and automation. It also offers direct import from Postman, Insomnia, OpenAPI specifications, curl commands, and Swagger files, easing migration for teams switching tools. Yaak's source code is MIT-licensed and publicly available on GitHub under the mountain-loop organization, so developers can self-build and use it entirely for free, including for commercial purposes, by compiling from source. The official pre-built desktop application is free for personal, non-commercial use with a 30-day full-featured trial and no credit card required. Using it at work requires a paid license: an Individual license costs $79 per year or $349 as a one-time lifetime purchase, covering commercial use on up to three devices with email support; a Business license costs $149 per user per year and adds transferable seats, SSO and user provisioning, and priority support for teams. Both paid tiers include a fallback license that keeps the currently installed version usable even after a subscription lapses. Yaak is best suited to individual developers and small to mid-sized engineering teams who want a fast, native, offline-capable API client without mandatory cloud accounts or telemetry.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '80059e68-8557-45a3-a76c-b2d0817a3a9c';

