-- ── Yakforms ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source form and survey builder that lets communities and organizations create and self-host online forms without relying on Google Forms.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Yakforms Review: Free Open-Source Form Builder Alternative to Google Forms$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn about Yakforms, a free, self-hostable open-source form and survey builder that grew out of Framasoft's Framaforms project, plus its features and license.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yakforms is a free, open-source form and survey builder that lets individuals and organizations create, publish, and collect responses from online forms without depending on a proprietary service like Google Forms or SurveyMonkey. The software originated as Framaforms, a tool officially released on October 5, 2016 by the French non-profit Framasoft as part of its De-google-ify Internet campaign, an initiative aimed at providing free, privacy-respecting alternatives to mainstream tech services. After maintaining Framaforms for roughly five years, Framasoft chose to hand the software back to its community around 2020 to 2021, renaming it Yakforms to avoid confusion between the software itself and the framaforms.org hosted service, which Framasoft continued to operate separately. Yakforms is built on Drupal 7 and makes extensive use of the Webform and Form Builder Drupal modules, and it is distributed under the GPL 2.0 license, meaning anyone can inspect, modify, self-host, and redistribute it. Because there is no central company behind Yakforms, development, translation, documentation, and interface design are driven by community contributors, and the project explicitly states that participation does not require technical skill. Functionally, Yakforms lets users build forms with a range of field types including text fields, text areas, checkboxes, and radio buttons, publish forms via a shareable web link or embed them on a website, collect and analyze submissions with basic built-in analytics and response visualizations, and export collected data as CSV or spreadsheet files for further processing. Organizations that want full control over their data can install their own private Yakforms instance rather than relying on a shared public instance, which supports the project's broader goal of contributing to a more decentralized internet. Notable adopters have included the French Ministry of Foreign Affairs and Framasoft's own hosted instances, and the ecosystem reportedly includes several active community-run instances used by thousands of form creators. Yakforms has no listed pricing because it is entirely free, community-supported software; any cost comes from self-hosting infrastructure or optional support arrangements an organization might set up independently. It is best suited to nonprofits, public institutions, and privacy-conscious organizations in French- and English-speaking communities who want a Google Forms alternative they can fully control and host themselves.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aedcb41b-b1e4-4c36-a18f-c2f220a1750c';

