-- ── yarn.social ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Decentralized, open-source social micro-blogging ecosystem built on the twtxt format, where users store and control their own posts as plain text files.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$yarn.social Review: Decentralized twtxt Social Network, Features and Cost$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn about yarn.social, a small open-source decentralized micro-blogging ecosystem built on twtxt, including its clients, servers, and free cost model.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$yarn.social is a decentralized, open-source ecosystem for social micro-blogging built around the twtxt text-file format, created around July 2020 by James Mills, a former Facebook engineer who also goes by the online handle prologic. The project began when Mills discovered twtxt, a simple specification in which a person's posts, or twts, are stored as lines in a plain text file, typically named twtxt.txt, hosted anywhere on the web. Mills built a client for it, then extended the concept into a fuller federated implementation with threaded conversations, mentions, and user discovery, initially launching as twtxt.net before rebranding to yarn.social to reduce confusion with the underlying twtxt specification. Unlike mainstream social networks, yarn.social has no central company, administrator, or algorithm controlling the experience. Every component in the ecosystem, including clients, servers known as pods, and supporting tools, is open source and released under the AGPLv3 license, so anyone can run their own pod, write their own client, or simply host a personal twtxt.txt file on any web server they control. The ecosystem includes multiple interchangeable clients, such as web applications, terminal-based clients, and desktop apps, along with a gateway that bridges yarn.social pods with the wider ActivityPub Fediverse, plus tools for search, discovery, and RSS or Atom feed bridging so users can follow traditional blogs alongside social posts. There is no cost to use yarn.social: there are no ads, no tracking, and no paywalls, consistent with its goal of being a genuinely user-owned alternative to corporate social platforms. Because yarn.social is a community-run, volunteer-maintained project rather than a company, there is no fixed headquarters, employee count, or revenue figure to report, and public information about its total user base is limited; it should be understood as a niche, technically-oriented project popular mainly among developers and decentralization enthusiasts rather than a mainstream social network. Its core appeal is philosophical as much as functional: posts belong to the user as literal files they control, discovery and following work across independently hosted pods rather than one company's servers, and the entire stack can be self-audited since it is fully open source.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '656d2c55-b8db-44a2-823d-f15eac0f5ffb';

