-- ── Yepic AI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI avatar and video generation platform for creating talking-avatar videos, real-time video agents, and multilingual dubbing at scale.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $20 per month (Basic plan), billed monthly or annually$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Yepic AI Review: AI Avatar Video Generator Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Yepic AI's AI avatar and video agent platform works, including pricing tiers, key features, and use cases for multilingual video creation.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yepic AI is an AI-powered video generation platform headquartered in London, United Kingdom, founded in 2019 by Aaron Jones and Jakub Langr. The company builds tools for creating synthetic video content featuring AI avatars, positioning itself as a video generator app used by more than 20,000 companies globally. Its core offering lets businesses generate videos of customizable digital avatars speaking scripted or dynamic content in more than 120 languages and dialects, using text-to-speech and lip-sync technology, including a proprietary dubbing engine called VidVoice for localizing existing video content into other languages. Beyond pre-recorded avatar videos, Yepic AI offers Video Agents, which are real-time, conversational AI avatars powered by large language models such as GPT-3.5, GPT-4, and GPT-4o, enabling interactive use cases like AI-driven customer support, sales conversations, and training simulations rather than static video output. The platform also includes facial recognition and emotion-detection technology designed to let avatars respond to a viewer's expressions during live interactions. Yepic AI's product suite is organized around Studio Express for quick, simple avatar video creation, Studio Pro for more advanced professional production, an API for developers who want to embed avatar generation into their own applications, and the Video Agents and VidVoice products for real-time and dubbing use cases respectively. Pricing is structured as a credit-based subscription with several tiers. The Basic plan starts at $20 per month or $200 per year and includes 200 monthly credits, up to 10 custom talking photos, and 3 real-time video agents with Express-only access. The Creator plan is $79 per month or $790 per year with 1,000 monthly credits, unlimited custom talking photos, 5 video agents with integrations, and both Pro and Express access plus API availability. Creator Plus, at $199 per month or $1,999 per year, is the most popular tier and adds 2,000 monthly credits, unlimited custom avatars and agents, and a computer vision add-on. Enterprise-oriented tiers include AI Employee at $499 per month, AI Team Member at $1,999 per month for team-based concurrent usage, and a fully custom Enterprise plan for large-scale organizations. All paid plans remove video watermarks and offer faster rendering. Yepic AI is best suited to marketing teams, training and enablement teams, and customer-facing organizations that want to scale personalized or multilingual video content without traditional video production costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '280ff386-aa0f-4c47-904e-14db30865949';

