-- ── Yeti-Switch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source SIP session border controller, Class 4 softswitch, and real-time VoIP billing system for telecom carriers and wholesale voice providers.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source); optional community support via Patreon$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Yeti-Switch Review: Open-Source SIP Softswitch and VoIP Billing$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Yeti-Switch, an open-source SIP session border controller, Class 4 softswitch, and real-time billing system built for VoIP carriers and wholesalers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yeti-Switch is an open-source SIP Session Border Controller, Class 4 softswitch, and real-time VoIP billing system built for telecom carriers and wholesale voice providers who need to interconnect, route, and bill voice traffic at scale. It is built on top of SEMS, a high-performance SIP/RTP application server, and its GitHub organization describes the goal as VoIP infrastructure software for humans, aimed at simplifying the traditionally complex world of carrier-grade telephony switching. The platform combines several functions that carriers typically need separate products for: carrier interconnection and session border control, dynamic call routing algorithms supporting least-cost routing, load balancing, and capacity control, integrated real-time billing for both wholesale and retail VoIP services, a number portability database, and STIR/SHAKEN call authentication support for combating caller ID spoofing and robocalls. It also offers Microsoft Teams Direct Routing compatibility, letting carriers connect their infrastructure to Microsoft Teams telephony, along with a REST API and a web-based customer portal for managing accounts and configuration. Yeti-Switch is maintained as a community open-source project rather than by a named commercial company; its code is hosted on GitHub under the yeti-switch organization, and the project accepts community support and donations through Patreon. Public documentation and an active community forum are available, along with a demo system for evaluating the platform before deployment. Because it is open source, Yeti-Switch can be deployed and used without licensing fees, though carriers typically need in-house or contracted SIP and telecom engineering expertise to deploy and operate it in production, given the technical complexity of Class 4 softswitch infrastructure. Public information about the project's founding date, the individuals or organization originally behind it, and its funding or team size is limited, consistent with it being a specialized, community-maintained open-source project serving a technical niche within the broader VoIP and telecom industry rather than a company with public-facing corporate details. It is best suited to VoIP carriers, wholesale voice providers, and telecom engineering teams who need carrier-grade routing and billing infrastructure they can self-host and fully control, rather than businesses looking for an end-user calling or contact center application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8734f0fa-231e-48e0-b9b8-faa68fe18c4b';

