-- ── Yext ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enterprise digital presence and location data platform that manages brand listings, reviews, local pages, and AI search visibility across the web.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $199 per year per location (Emerging plan)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$1,000-2,500 employees (publicly traded, NYSE: YEXT)$q$, company_size),
  headquarters = COALESCE($q$New York, New York$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Yext Review: Enterprise Local SEO and AI Search Visibility Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Yext offers: an enterprise platform for managing location listings, reviews, local pages, and AI search visibility, plus its pricing and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Yext is a publicly traded enterprise software company, listed on the New York Stock Exchange under the ticker YEXT since 2017, founded in 2006 and headquartered in New York City. The company built its reputation as a location data and local SEO platform that helps multi-location brands keep their business information, such as addresses, hours, and phone numbers, accurate and consistent across search engines, maps, directories, and voice assistants. Over time Yext has expanded into what it now calls an agentic marketing platform, reflecting the shift in search behavior toward AI assistants and large language models alongside traditional search engines. Its core product is a Knowledge Graph that centralizes and verifies brand data as the single source of truth, which then feeds several connected modules: Listings Management syndicates and corrects business information across web directories and maps, Reviews handles reputation management and review monitoring across platforms, Pages generates search-optimized local landing pages for individual locations, and Content Distribution pushes verified content out to directories, maps, social platforms, and increasingly to large language models so AI assistants surface accurate brand information. A newer product called Scout provides real-time monitoring of how a brand appears in AI-powered search results and competitive intelligence around AI search visibility, reflecting Yext's positioning around the rise of AI-driven search and answer engines. Yext reports serving brands that collectively manage more than 4 million locations worldwide, with enterprise customers including Samsung, FedEx, Domino's, and IHG Hotels. Yext's published pricing follows a tiered, per-location annual subscription model: Emerging starts at $199 per year per location for basic listing distribution to around 30 directory sites; Essential is $449 per year and adds detailed listing management on premium sites like Google, Apple, Bing, Yahoo, and Yelp; Complete is $499 per year; and Premium is $999 per year for the most comprehensive feature set. Costs scale with the number of locations managed, and larger mid-market and enterprise customers typically negotiate custom volume-based contracts rather than paying the published per-location rates. Employee counts reported across data providers range from roughly 1,100 to over 2,500, reflecting differences in reporting dates and methodology. Yext is best suited to multi-location brands, franchises, healthcare systems, financial institutions, and large retailers that need centralized control over how their business information appears across an increasingly fragmented and AI-influenced search landscape.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e37c82e0-4240-4f11-9aae-4a179e6cd032';

