INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$WYSIWYG and wiki-syntax editing$q$, $q$Edit content visually or with lightweight wiki markup, with OpenDocument-based import and export for interoperability with office suites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Built-in application framework$q$, $q$Turn wiki pages into structured data and scripted mini-applications without needing a separate low-code platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Granular rights management$q$, $q$Control read, edit, and admin permissions at the wiki, space, or page level for fine-grained access control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Full version history and annotations$q$, $q$Every page change is tracked and reversible, and users can leave inline annotations and comments for collaborative review.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Wiki farms$q$, $q$Run multiple independent wikis for different teams or departments from a single installation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Extension marketplace$q$, $q$Add community-built applications, macros, and integrations through XWiki's extension repository.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$RESTful API$q$, $q$Integrate XWiki content and structured data with external systems and custom tooling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Enterprise SSO on paid tiers$q$, $q$Business and Enterprise plans add OIDC and SAML single sign-on plus migration tooling from Confluence and SharePoint.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Free, fully open-source core with no per-user pricing or seat caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Doubles as a lightweight application-building platform, not just a documentation wiki$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Strong version history and granular permissions suited to enterprise knowledge bases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Can be fully self-hosted for organizations with data residency or control requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Over two decades of continuous open-source development with an active extension ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$The interface feels dated next to modern SaaS knowledge tools like Notion or Confluence$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Self-hosting requires ongoing server maintenance and technical know-how$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Confluence and SharePoint migration tools are reserved for Business-tier and above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Building custom applications on top of wiki pages has a learning curve for non-developers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Is XWiki free to use?$q$, $q$Yes. The Community edition is free and open-source and can be self-hosted with no limit on users. Paid plans add support, security patches, and cloud hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Is XWiki open source?$q$, $q$Yes, XWiki is distributed under the LGPL license and its source code is publicly available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Can XWiki replace Confluence?$q$, $q$Many organizations use XWiki as a self-hosted Confluence alternative, and paid tiers include dedicated tooling to help migrate content from Confluence.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Does XWiki offer managed cloud hosting?$q$, $q$Yes, XWiki SAS offers cloud-hosted plans starting with the Starter tier, in addition to self-hosted deployment.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Can XWiki be used to build applications, not just wiki pages?$q$, $q$Yes, XWiki includes a scripting and macro layer that lets users create structured data forms and small internal applications inside the wiki.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Does XWiki support single sign-on?$q$, $q$OIDC and SAML single sign-on are available starting at the Business tier and above.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$How is XWiki different from MediaWiki?$q$, $q$XWiki adds structured data, application-building macros, and enterprise permissions on top of standard wiki editing, whereas MediaWiki is closer to a pure documentation wiki.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Who is behind XWiki?$q$, $q$XWiki is developed by XWiki SAS, a company founded in 2004 and headquartered in Paris, France, with the software released under an open-source license.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Enterprise knowledge management$q$, $q$Centralize company documentation, policies, and processes in a searchable, permission-controlled wiki that can be self-hosted for data control.$q$, $q$IT and knowledge management teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Internal software documentation$q$, $q$Maintain technical documentation, runbooks, and specifications with version history and structured data alongside free-form pages.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Lightweight internal applications$q$, $q$Build simple forms, trackers, and workflows directly on wiki pages without adopting a separate low-code tool.$q$, $q$Operations and business teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Community$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted only","Unlimited users","Full open-source feature set","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Starter$q$, $q$Contact for pricing$q$, $q$annual$q$, NULL, $q$["Cloud hosting only","Up to 25 users","Online ordering","Community extensions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Basic$q$, $q$From approximately 2 euros per user per month$q$, $q$annual$q$, NULL, $q$["Cloud or on-premise deployment","Up to 1,000 users","Early security patches","Antivirus application"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Business$q$, $q$Contact for pricing$q$, $q$annual$q$, NULL, $q$["Cloud or on-premise deployment","Up to 10,000 users","OIDC and SAML SSO","Confluence and SharePoint migration tools"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Unlimited users","Kubernetes and advanced deployment support","Dedicated account management","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$overview$q$, $q$What Is XWiki$q$, 2, ARRAY[$q$XWiki is an open-source enterprise wiki platform that has been under continuous development since 2004. It is built and maintained by XWiki SAS, a company based in Paris, France, and is distributed under the LGPL open-source license, meaning the core software can be downloaded, self-hosted, and used commercially without paying a license fee.$q$, $q$What sets XWiki apart from simpler wiki tools is its dual identity as both a documentation platform and an application framework. Pages can contain structured data, forms, and scripted macros, which means teams can build small internal applications, such as inventories, issue trackers, or approval workflows, directly inside the wiki rather than relying on a separate tool.$q$, $q$XWiki is commonly used by IT departments, universities, government agencies, and software teams that want an enterprise-grade knowledge base they fully control, either self-hosted on their own infrastructure or run on XWiki's managed cloud offering.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$XWiki supports both WYSIWYG editing and wiki syntax, along with OpenDocument-based import and export, page annotations, tagging, and threaded comments, making it usable by both technical and non-technical staff.$q$, $q$Permissions are granular, letting administrators control access at the wiki, space, or individual page level, and every edit is versioned so changes can be reviewed or rolled back at any time.$q$, $q$The platform supports wiki farms, meaning a single installation can host many separate wikis for different teams or departments, and it exposes a RESTful API and extension marketplace so it can be integrated with external systems and extended with community-built applications.$q$, $q$Higher-tier commercial plans add single sign-on through OIDC or SAML, dedicated migration tooling from Confluence and SharePoint, and priority support with a named account manager.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The XWiki Community edition is entirely free and can be self-hosted with no cap on the number of users, which is the option most technical teams start with.$q$, $q$For organizations that want support, security patches, or managed cloud hosting, XWiki SAS sells four annual subscription tiers: Starter for up to 25 users on the cloud, Basic for up to 1,000 users on cloud or on-premise, Business for up to 10,000 users with SSO and migration tools, and Enterprise for unlimited users with advanced deployment support.$q$, $q$Professional services such as consulting and training are billed separately on a per-day basis, and open-source projects or NGOs can qualify for discounted support pricing and free entry-level cloud hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb6f9f95-9f4c-4661-825d-e8c01f5894f4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Multi-protocol support$q$, $q$Send REST, GraphQL, gRPC, WebSocket, and Server-Sent Events requests from one client.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Local-first storage$q$, $q$Collections and requests are saved as plain text files on your machine, with no mandatory cloud account.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Git-friendly collections$q$, $q$Version and share API collections through a standard Git repository instead of a proprietary sync service.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Encrypted secrets$q$, $q$Store API keys and tokens locally using ChaCha20-Poly1305 encryption.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Import from other tools$q$, $q$Bring in existing collections directly from Postman, Insomnia, OpenAPI, curl, and Swagger.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Request chaining and templating$q$, $q$Chain requests together and reuse dynamic variables across a collection.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$CLI and automation support$q$, $q$Run and script requests outside the GUI for CI or agent-driven workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Customizable themes$q$, $q$Choose from more than 30 interface themes to personalize the workspace.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Free for personal use with no forced account creation or cloud sync$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Fully offline-capable, local-first architecture appeals to privacy-conscious developers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$MIT-licensed source code allows free commercial use for those who self-build$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Git-native collection storage simplifies team version control$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Straightforward import from Postman, Insomnia, and OpenAPI eases migration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Commercial use of the pre-built app requires a paid license even for solo freelancers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Newer product (launched 2024) with a smaller ecosystem than Postman$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Some team collaboration features are limited to the paid Business tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Detailed public information on company size and roadmap is limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Is Yaak free?$q$, $q$Yaak is free for personal, non-commercial use. A paid Individual or Business license is required for use at work.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Is Yaak open source?$q$, $q$Yes, Yaak's source code is MIT-licensed and available on GitHub, allowing free use by anyone who builds it from source.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$What protocols does Yaak support?$q$, $q$Yaak supports HTTP/REST, GraphQL, gRPC, WebSocket, and Server-Sent Events requests.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Can I import my Postman or Insomnia collections into Yaak?$q$, $q$Yes, Yaak supports direct import from Postman, Insomnia, OpenAPI, curl, and Swagger.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Who created Yaak?$q$, $q$Yaak was built by Mountain Loop Labs, founded by the developer who previously created and sold Insomnia.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Does Yaak store my data in the cloud?$q$, $q$No, Yaak is local-first and stores requests and collections as plain text files on your machine rather than in a mandatory cloud account.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$How much does the Business license cost?$q$, $q$The Business license is $149 per user per year and includes SSO, user provisioning, and priority support.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Does Yaak work offline?$q$, $q$Yes, Yaak is designed to work fully offline without requiring an internet connection.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$API development and debugging$q$, $q$Build, send, and inspect REST, GraphQL, and gRPC requests while developing backend services.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Team API collection sharing$q$, $q$Store and version API collections in Git so a team can review and collaborate on request changes like code.$q$, $q$Small to mid-sized engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Offline or privacy-sensitive testing$q$, $q$Test internal or sensitive APIs without sending collection data to a third-party cloud service.$q$, $q$Security-conscious developers and regulated teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Personal, non-commercial use","30-day full trial of all features","No credit card required","Full desktop application access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Individual$q$, $q$$79 per year or $349 lifetime$q$, $q$annual or one-time$q$, NULL, $q$["Commercial use for one person","Use on up to 3 devices","Email support","Fallback license after cancellation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$Business$q$, $q$$149 per user per year$q$, $q$annual$q$, NULL, $q$["Transferable team licenses","SSO and user provisioning","Priority email support","Premium roadmap influence"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$overview$q$, $q$What Is Yaak$q$, 2, ARRAY[$q$Yaak is a desktop API client for building and testing HTTP, GraphQL, gRPC, WebSocket, and Server-Sent Events requests. It was created by Mountain Loop Labs, founded by the developer behind Insomnia, and launched in January 2024 as a local-first alternative to cloud-account-based API tools.$q$, $q$The core idea behind Yaak is that developer tools should not require an account, an internet connection, or trust in a third-party cloud to function. Requests and collections are stored as plain text files on the local machine, which makes them naturally version-controllable with Git and portable between machines.$q$, $q$Yaak targets individual developers and small engineering teams who want a fast, native API client with strong privacy defaults, while still offering a paid commercial license and team features for organizations that need them.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Yaak supports multiple protocols in a single client, including REST, GraphQL, gRPC, WebSocket, and Server-Sent Events, so developers do not need separate tools for each type of API.$q$, $q$Its local-first architecture stores collections as plain text and integrates with Git for version control, while secrets and credentials can be stored using ChaCha20-Poly1305 encryption.$q$, $q$Additional productivity features include request chaining and dynamic templating with variables, multiple windows for parallel projects, a CLI and agent support for automation, and over 30 customizable interface themes.$q$, $q$Migration is supported through direct import from Postman, Insomnia, OpenAPI, curl, and Swagger, making it straightforward to move existing collections into Yaak.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yaak's source code is MIT-licensed, so developers can build it from source and use it for free, including commercially, without purchasing a license.$q$, $q$The official pre-built desktop application is free for personal, non-commercial use and includes a 30-day full-featured trial with no credit card required.$q$, $q$Commercial use requires a paid license: Individual is $79 per year or $349 as a one-time lifetime purchase for a single person on up to three devices, while Business is $149 per user per year and adds transferable licenses, SSO, user provisioning, and priority support for teams. Non-profits and bulk purchasers can contact Yaak's sales team for discounts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80059e68-8557-45a3-a76c-b2d0817a3a9c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Drag-and-drop form fields$q$, $q$Build forms using text fields, text areas, checkboxes, and radio buttons without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Shareable and embeddable forms$q$, $q$Publish forms via a direct link or embed them on an existing website.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Response analytics$q$, $q$Review submissions with basic charts and graphs directly inside the tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$CSV and spreadsheet export$q$, $q$Download collected responses for further processing in external tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Self-hosting support$q$, $q$Install a private instance on your own server to keep full control of form data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$GPL 2.0 open-source license$q$, $q$Freely inspect, modify, and redistribute the software under an open-source license.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Community-driven development$q$, $q$Development, translation, and documentation are maintained by volunteer contributors.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Completely free with no subscription or usage fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Self-hostable, giving organizations full control over respondent data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Simple, no-code form-building interface suited to non-technical users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Open-source and community-maintained, reducing vendor lock-in risk$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Proven track record through public institution and nonprofit adoption$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Built on Drupal 7, an aging technology stack compared to modern form builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$No dedicated company behind it, so support depends on community responsiveness$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Interface and feature set are more basic than commercial tools like Typeform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Self-hosting requires server administration knowledge$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Is Yakforms free?$q$, $q$Yes, Yakforms is completely free and open-source under the GPL 2.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$What is the relationship between Yakforms and Framaforms?$q$, $q$Yakforms is the renamed continuation of the Framaforms software, originally released by Framasoft in 2016 and handed back to the community around 2020 to 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Can I self-host Yakforms?$q$, $q$Yes, organizations can install their own private Yakforms instance on their own server for full control over data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$What technology is Yakforms built on?$q$, $q$Yakforms is built on Drupal 7, using the Webform and Form Builder Drupal modules.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Can I export form responses?$q$, $q$Yes, responses can be exported as CSV or spreadsheet files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Who maintains Yakforms?$q$, $q$Yakforms is maintained by a volunteer community rather than a single company, after Framasoft handed the project over.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Is Yakforms available in English?$q$, $q$Yes, while the project originated in the French-speaking Framasoft community, Yakforms is available in English as well.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Nonprofit and community surveys$q$, $q$Collect feedback or registrations from community members using a self-hosted, ad-free form tool.$q$, $q$Nonprofits and community organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Public sector data collection$q$, $q$Run official forms and surveys on infrastructure the organization controls, avoiding third-party data processors.$q$, $q$Government and public institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Privacy-conscious form building$q$, $q$Replace Google Forms with a self-hosted alternative for individuals and small teams wanting full data ownership.$q$, $q$Privacy-focused individuals and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted or community instance use","Unlimited forms","CSV and spreadsheet export","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$overview$q$, $q$What Is Yakforms$q$, 2, ARRAY[$q$Yakforms is a free, open-source form and survey builder that grew out of Framaforms, a tool released in 2016 by the French non-profit Framasoft as part of its campaign to offer alternatives to mainstream tech services like Google Forms.$q$, $q$After maintaining Framaforms for about five years, Framasoft returned stewardship of the software to its community, renaming it Yakforms to separate the open-source project from the framaforms.org hosted service it continued to run.$q$, $q$Built on Drupal 7 and licensed under GPL 2.0, Yakforms can be self-hosted by any organization that wants full ownership of its form and survey data instead of relying on a third-party SaaS provider.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can build forms with common field types such as text fields, text areas, checkboxes, and radio buttons, then publish them through a shareable web link or by embedding the form directly on a website.$q$, $q$Collected responses can be reviewed through built-in analytics with basic graphs and visualizations, and exported as CSV or spreadsheet files for deeper analysis elsewhere.$q$, $q$Because Yakforms is self-hostable, organizations can install their own private instance to keep full control of respondent data, which has made it popular with public institutions and privacy-focused nonprofits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yakforms is entirely free software with no paid tiers, subscriptions, or licensing fees, since it is released under the GPL 2.0 open-source license.$q$, $q$Any cost associated with using Yakforms comes from self-hosting infrastructure, such as server and maintenance costs, rather than from the software itself.$q$, $q$Community-run public instances are also available for organizations that prefer not to self-host, though data control is stronger when running a private installation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aedcb41b-b1e4-4c36-a18f-c2f220a1750c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Plain-text post ownership$q$, $q$Posts live as lines in a twtxt.txt file the user hosts and controls, rather than in a corporate database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Federated pods$q$, $q$Independent servers, called pods, can be self-hosted and interoperate with each other rather than relying on one central service.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Multiple clients$q$, $q$Choose from web, terminal, and desktop clients that all work with the same open twtxt-based feeds.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$ActivityPub gateway$q$, $q$Bridges yarn.social with the broader Fediverse, including platforms like Mastodon.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Threaded conversations and mentions$q$, $q$Adds structured replies and mentions on top of the simple twtxt format.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$RSS and Atom bridging$q$, $q$Follow traditional blogs alongside social posts within the same feed reader experience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Fully open specifications$q$, $q$Open specs mean anyone can build a compatible client or server without permission from a gatekeeper.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Completely free with no ads, tracking, or paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Users genuinely own their content as plain text files they control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Fully decentralized with no single company or server that can shut the network down$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Open specifications allow anyone to build compatible clients or servers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Bridges to the wider Fediverse through ActivityPub$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Very small, niche user base compared to mainstream social platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$No official company or support channel, since it is entirely community-run$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Setup and self-hosting require more technical comfort than a typical social app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Public data on total users, activity levels, and growth is limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Is yarn.social free?$q$, $q$Yes, yarn.social is completely free with no ads, tracking, or paywalls.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Who created yarn.social?$q$, $q$It was created around 2020 by James Mills, also known by the handle prologic, building on the earlier twtxt specification.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Is yarn.social open source?$q$, $q$Yes, every component, including clients and server software known as pods, is open source under the AGPLv3 license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Does yarn.social connect to Mastodon or the Fediverse?$q$, $q$Yes, an ActivityPub gateway bridges yarn.social pods with the wider Fediverse, including Mastodon.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$What is twtxt?$q$, $q$twtxt is the simple text-file specification that yarn.social is built on, where a user's posts are stored as lines in a plain text file they host.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Can I self-host my own yarn.social pod?$q$, $q$Yes, anyone can run their own pod since the server software is open source and self-hostable.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$How large is the yarn.social community?$q$, $q$It is a small, niche community focused on developers and decentralization enthusiasts; precise user numbers are not publicly documented.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Decentralized personal blogging and micro-posting$q$, $q$Publish short posts as a plain text file hosted on personal infrastructure instead of a corporate platform.$q$, $q$Independent bloggers and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Self-hosted community feeds$q$, $q$Run a private pod for a small group or community that wants a social feed without a third-party platform.$q$, $q$Small technical communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Fediverse-connected posting$q$, $q$Post from a self-hosted feed while still reaching followers on Mastodon and other ActivityPub platforms.$q$, $q$Decentralization and open-web enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted pods and clients","No ads or tracking","ActivityPub Fediverse bridging","Community-driven support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$overview$q$, $q$What Is yarn.social$q$, 2, ARRAY[$q$yarn.social is a decentralized, open-source social micro-blogging ecosystem built on top of twtxt, a simple specification where a person's posts are stored as lines in a plain text file hosted on any web server they control.$q$, $q$The project was created around July 2020 by James Mills, a former Facebook engineer who built an extended, federated implementation of twtxt with threaded conversations, mentions, and user discovery, originally as twtxt.net before rebranding to yarn.social.$q$, $q$There is no central company behind yarn.social. It is maintained as a community, open-source project with no algorithm, no central server, and no single point of control, making it a niche alternative to mainstream corporate social networks rather than a mass-market product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Posts are stored as plain text twtxt.txt files that users host themselves, meaning content ownership sits with the individual rather than a platform operator.$q$, $q$The ecosystem offers multiple interchangeable clients, including web apps, terminal clients, and desktop applications, along with independently run servers called pods that anyone can host.$q$, $q$An ActivityPub gateway connects yarn.social to the wider Fediverse, and additional tools support search, discovery, and bridging RSS or Atom feeds so users can follow traditional blogs alongside social posts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$yarn.social is entirely free to use, with no ads, no tracking, and no paywalls anywhere in the ecosystem.$q$, $q$Because every component is open source under the AGPLv3 license, individuals and organizations can self-host their own pod or client at no licensing cost, with the only expense being their own server infrastructure.$q$, $q$There are no commercial pricing tiers, since the project is community-maintained rather than operated by a company selling a product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('656d2c55-b8db-44a2-823d-f15eac0f5ffb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$AI avatar video creation$q$, $q$Generate videos of customizable digital avatars speaking scripted content in Studio Express or Studio Pro.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Real-time Video Agents$q$, $q$Interactive, conversational AI avatars powered by large language models like GPT-4o for live use cases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Multilingual support$q$, $q$Create avatar videos in more than 120 languages and dialects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$VidVoice dubbing$q$, $q$Proprietary lip-sync dubbing technology for localizing existing video content into other languages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Emotion detection$q$, $q$Facial recognition technology that lets avatars respond to a viewer's expressions during live sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Developer API$q$, $q$Integrate avatar and video generation capabilities directly into custom applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Custom talking photos and avatars$q$, $q$Turn photos into custom talking avatars for personalized video content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Credit-based tiered plans$q$, $q$Scale usage from individual creators up to enterprise teams through credit allowances per plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Supports more than 120 languages, useful for global marketing and training content$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Real-time Video Agents extend the platform beyond static video into interactive use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Offers both simple (Express) and advanced (Pro) creation modes for different skill levels$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Developer API allows embedding avatar generation into other products$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Wide range of pricing tiers from individual creators to large enterprises$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Credit-based pricing can be difficult to estimate costs against for heavy usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Lower-tier plans limit access to Pro features, API, and number of avatars or agents$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Enterprise tiers are priced significantly higher than typical AI video tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Public information on company size and total funding is limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$What is Yepic AI used for?$q$, $q$Yepic AI is used to create AI avatar videos and real-time conversational video agents for marketing, training, and customer engagement.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$How much does Yepic AI cost?$q$, $q$Plans start at $20 per month for the Basic tier and scale up to custom Enterprise pricing, based on monthly credits and features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Does Yepic AI support multiple languages?$q$, $q$Yes, Yepic AI supports avatar video creation and dubbing in more than 120 languages and dialects.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$What are Yepic AI Video Agents?$q$, $q$Video Agents are real-time, conversational AI avatars powered by large language models like GPT-4o that can interact live rather than following a fixed script.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Does Yepic AI offer an API?$q$, $q$Yes, an API is available starting on the Creator plan for developers who want to integrate avatar video generation into their own applications.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Who founded Yepic AI?$q$, $q$Yepic AI was founded in 2019 by Aaron Jones and Jakub Langr and is headquartered in London, United Kingdom.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$What is VidVoice?$q$, $q$VidVoice is Yepic AI's proprietary lip-sync dubbing technology used to localize existing video content into other languages.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Is there a free trial for Yepic AI?$q$, $q$Yepic AI offers a demo through its website; a persistent free plan is not listed among its published pricing tiers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Multilingual marketing videos$q$, $q$Produce localized marketing and product videos featuring AI avatars speaking in more than 120 languages.$q$, $q$Marketing teams at global brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$AI-driven customer engagement$q$, $q$Deploy real-time conversational Video Agents for customer support, sales, or onboarding interactions.$q$, $q$Customer support and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Corporate training content$q$, $q$Scale training and enablement video production using avatar-led content instead of traditional filming.$q$, $q$L and D and enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Basic$q$, $q$$20 per month or $200 per year$q$, $q$monthly or annual$q$, NULL, $q$["200 monthly credits","Up to 10 custom talking photos","3 real-time video agents","Express access only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Creator$q$, $q$$79 per month or $790 per year$q$, $q$monthly or annual$q$, NULL, $q$["1,000 monthly credits","Unlimited custom talking photos","5 video agents with integrations","Pro and Express access plus API"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Creator Plus$q$, $q$$199 per month or $1,999 per year$q$, $q$monthly or annual$q$, NULL, $q$["2,000 monthly credits","Unlimited custom avatars","Unlimited agents","Computer vision add-on"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$AI Employee$q$, $q$$499 per month or $4,990 per year$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited features","1 concurrent session","Human onboarding","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$AI Team Member$q$, $q$$1,999 per month or $19,990 per year$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited features","5 concurrent sessions","Team support via Slack or WhatsApp","Priority onboarding"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Fully customizable feature set","Scales for large organizations","Dedicated account management","Custom integrations"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$overview$q$, $q$What Is Yepic AI$q$, 2, ARRAY[$q$Yepic AI is a London-based AI video generation platform founded in 2019 by Aaron Jones and Jakub Langr. It lets businesses create videos of customizable AI avatars speaking scripted content, and says it is used by more than 20,000 companies worldwide.$q$, $q$The platform generates avatar-led videos in more than 120 languages and dialects using text-to-speech and lip-sync technology, and also offers a dedicated multilingual dubbing engine called VidVoice for localizing existing footage.$q$, $q$Beyond static avatar videos, Yepic AI offers real-time conversational Video Agents built on large language models, extending the platform from one-way video production into interactive, AI-driven video conversations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Studio Express and Studio Pro provide different levels of complexity for creating avatar videos, from quick simple clips to more advanced professional production workflows.$q$, $q$Video Agents use large language models such as GPT-4o to power real-time, conversational AI avatars that can respond dynamically rather than following a fixed script, supported by facial recognition and emotion-detection technology.$q$, $q$An API is available for developers who want to integrate avatar and video generation directly into their own applications or products, and VidVoice provides multilingual dubbing for existing video content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280ff386-aa0f-4c47-904e-14db30865949', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yepic AI uses a credit-based subscription model with tiers ranging from Basic at $20 per month up through Creator and Creator Plus at $79 and $199 per month respectively, each unlocking more monthly credits, avatars, and video agents.$q$, $q$Enterprise-oriented plans, AI Employee and AI Team Member, are priced at $499 and $1,999 per month and add unlimited feature access with human onboarding, dedicated support channels, and multiple concurrent sessions for teams.$q$, $q$A fully custom Enterprise plan is available for large organizations with specific scaling or integration needs, and all paid tiers remove watermarks and offer faster video rendering than lower tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$SIP session border control$q$, $q$Handles carrier interconnection and secures the boundary between telecom networks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Class 4 softswitch routing$q$, $q$Dynamic routing algorithms with least-cost routing, load balancing, and capacity control.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Real-time VoIP billing$q$, $q$Integrated billing engine for both wholesale and retail voice services.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Number portability database$q$, $q$Built-in support for managing ported phone numbers across carriers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$STIR/SHAKEN authentication$q$, $q$Call authentication support to reduce caller ID spoofing and robocalls.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Microsoft Teams Direct Routing$q$, $q$Compatibility for connecting carrier infrastructure to Microsoft Teams telephony.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$REST API$q$, $q$Programmatic access for automating configuration, routing, and billing management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Web-based customer portal$q$, $q$Self-service portal for account and configuration management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Free, open-source access to carrier-grade softswitch and billing infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Combines session border control, routing, and billing in a single platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Supports modern telecom requirements like STIR/SHAKEN and Teams Direct Routing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$REST API and customer portal support both automation and self-service management$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Active open-source community with documentation, forum, and demo access$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Requires significant SIP and telecom engineering expertise to deploy and operate$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$No named commercial company or official paid support tier for enterprises$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Public information about the project's founding and team is limited$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Not suited to non-technical users or businesses needing a simple hosted phone system$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Is Yeti-Switch free?$q$, $q$Yes, Yeti-Switch is open-source software that can be deployed without licensing fees, with optional community support via Patreon.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$What is Yeti-Switch used for?$q$, $q$It is used by telecom carriers and wholesale VoIP providers as a Class 4 softswitch, session border controller, and real-time billing system.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Does Yeti-Switch support STIR/SHAKEN?$q$, $q$Yes, it includes STIR/SHAKEN call authentication support to help reduce caller ID spoofing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Can Yeti-Switch connect to Microsoft Teams?$q$, $q$Yes, it offers Microsoft Teams Direct Routing compatibility.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$What underlying technology does Yeti-Switch use?$q$, $q$It is built on SEMS, a high-performance SIP and RTP application server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Does Yeti-Switch include billing features?$q$, $q$Yes, it has an integrated real-time billing system for both wholesale and retail VoIP services.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Who maintains Yeti-Switch?$q$, $q$It is maintained as a community open-source project, with code hosted on GitHub and support accepted through Patreon.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Wholesale voice carrier routing$q$, $q$Route and terminate large volumes of voice traffic between interconnected carriers with least-cost routing.$q$, $q$Wholesale VoIP carriers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Retail VoIP billing$q$, $q$Bill retail telephony customers in real time using the platform's integrated billing engine.$q$, $q$Retail VoIP service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Carrier-grade session border control$q$, $q$Secure and manage SIP interconnection points between telecom networks.$q$, $q$Telecom network engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted deployment","Full SIP softswitch and billing feature set","Community forum and documentation","Optional Patreon-based community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$overview$q$, $q$What Is Yeti-Switch$q$, 2, ARRAY[$q$Yeti-Switch is an open-source SIP Session Border Controller, Class 4 softswitch, and real-time VoIP billing system built on the SEMS SIP/RTP application server. It is aimed at telecom carriers and wholesale voice providers who need to interconnect and route large volumes of voice traffic.$q$, $q$Rather than being a single-purpose tool, Yeti-Switch combines session border control, call routing, and billing in one platform, which is a common requirement for carriers running Class 4 switching infrastructure between other telecom networks.$q$, $q$The project is maintained by the open-source Yeti-Switch community and hosted on GitHub, with documentation, a demo environment, and a public forum available for evaluation and support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core carrier features include dynamic routing with least-cost routing, load, and capacity control, along with integrated real-time billing for both wholesale and retail VoIP services.$q$, $q$The platform includes a number portability database, STIR/SHAKEN call authentication for combating spoofed caller ID and robocalls, and Microsoft Teams Direct Routing compatibility for connecting to Teams telephony.$q$, $q$Administration is handled through a REST API and a web-based customer portal, giving carriers programmatic and self-service ways to manage accounts, routes, and billing configuration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yeti-Switch is free, open-source software with no licensing cost, since its code is publicly available under the yeti-switch GitHub organization.$q$, $q$The project accepts voluntary community support and donations through Patreon rather than charging for the software itself.$q$, $q$Organizations deploying Yeti-Switch in production should budget for their own hosting infrastructure and SIP or telecom engineering expertise, since no official paid support tier is advertised on the project's site.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8734f0fa-231e-48e0-b9b8-faa68fe18c4b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
