INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Dynamic report builder$q$, $q$Create custom reports from CRM and ERP data to support business decisions.$q$, 1);
