INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Unlimited users$q$, $q$No per-seat licensing fees or user caps, since the platform is fully open source.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Email integration$q$, $q$Connect email accounts directly into the CRM for centralized communication tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Offline installation$q$, $q$Deploy YetiForce in environments without requiring constant internet access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Multi-language support$q$, $q$Supports more than 35 languages for international teams and deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Responsive interface$q$, $q$Usable across desktop and mobile devices with an adaptive interface.$q$, 7);
