INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Broad functional scope spanning CRM and ERP rather than sales-only$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Highly customizable with over 80 modules and configurable workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Proven at scale, with deployments exceeding 12,500 users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Recognized on review platforms including G2, Capterra, and SourceForge$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Requires self-hosting and technical setup, unlike managed SaaS CRMs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Broad feature set can feel complex for smaller teams with simple needs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$No official managed cloud version, so IT resources are needed for maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Public data on the company's size and financials beyond its Polish registration is limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Is YetiForce free?$q$, $q$Yes, YetiForce is completely free and open source with no per-user licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Is YetiForce open source?$q$, $q$Yes, the software is open source and was originally branched from Vtiger CRM before diverging significantly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Who founded YetiForce?$q$, $q$YetiForce was founded in 2014 by Blazej Pabiszczak and is headquartered in Warsaw, Poland.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$How many modules does YetiForce include?$q$, $q$YetiForce ships with more than 80 ready-made modules covering marketing, sales, projects, support, finance, logistics, and HR.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Does YetiForce limit the number of users?$q$, $q$No, YetiForce places no restriction on the number of users an organization can add.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$How many companies use YetiForce?$q$, $q$According to the vendor, roughly 23,000 companies in more than 100 countries use YetiForce.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Does YetiForce require self-hosting?$q$, $q$Yes, YetiForce is typically self-hosted, so organizations need their own infrastructure and technical resources to deploy and maintain it.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Is YetiForce suited for large enterprises?$q$, $q$Yes, YetiForce has been deployed at scale, including a documented deployment exceeding 12,500 users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$All-in-one CRM and ERP deployment$q$, $q$Replace multiple point solutions with a single free platform covering sales, support, finance, and operations.$q$, $q$Medium and large businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Government and institutional process management$q$, $q$Manage departmental processes and reporting on a self-hosted, license-fee-free platform.$q$, $q$Government agencies and public institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Cost-sensitive CRM adoption$q$, $q$Adopt a full-featured CRM without per-user licensing costs by self-hosting the open-source platform.$q$, $q$Budget-conscious growing businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited users","80-plus business modules","Self-hosted deployment","Community documentation and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$overview$q$, $q$What Is YetiForce$q$, 2, ARRAY[$q$YetiForce is a free, open-source CRM and ERP platform founded in 2014 in Warsaw, Poland by Blazej Pabiszczak. It was originally branched from Vtiger CRM but has since diverged significantly through years of independent development.$q$, $q$Unlike a narrowly scoped sales CRM, YetiForce is designed as a broader business management platform, offering more than 80 modules that span marketing, sales, project management, support, finance, logistics, and HR.$q$, $q$The platform is used by an estimated 23,000 companies across more than 100 countries, according to the vendor, including large enterprises and government institutions, with its largest known deployment exceeding 12,500 users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$YetiForce includes ready-made modules across marketing, sales, project management, customer support, finance, logistics, HR, and reporting, giving organizations a single system for multiple departments.$q$, $q$A dynamic report builder lets users create custom reports from operational data, while customizable workflows allow the system to be adapted to specific business processes without a full custom build.$q$, $q$Additional capabilities include email integration, offline installation support, a responsive user interface, and support for more than 35 languages, reflecting its international deployment base.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$YetiForce is completely free and open source, with no license fee and no restriction on the number of users an organization can add.$q$, $q$Costs come primarily from self-hosting infrastructure and implementation effort, since YetiForce is typically self-deployed rather than offered as a managed SaaS product.$q$, $q$Organizations that want additional customization or professional support can arrange this independently, as YetiForce does not publish tiered commercial pricing plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad091561-b390-481a-bf66-f43ea55efb9d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
