INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Best suited to multi-location brands, less cost-effective for single-location businesses$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$What does Yext do?$q$, $q$Yext manages a brand's business listings, reviews, local pages, and visibility across search engines, maps, and increasingly AI-powered search results.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$How much does Yext cost?$q$, $q$Published plans range from $199 per year per location on the Emerging tier up to $999 per year on the Premium tier, with enterprise buyers often negotiating custom pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$When was Yext founded?$q$, $q$Yext was founded in 2006 and is headquartered in New York City.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Is Yext a public company?$q$, $q$Yes, Yext has traded on the New York Stock Exchange under the ticker YEXT since 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$What is the Yext Knowledge Graph?$q$, $q$It is Yext's centralized, verified source of truth for a brand's location and business data, which feeds its other products like listings and pages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Does Yext help with AI search visibility?$q$, $q$Yes, Yext's Scout product monitors how a brand appears in AI-powered search results and provides competitive intelligence around AI search.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Who uses Yext?$q$, $q$Yext is used by multi-location brands and enterprises including Samsung, FedEx, Domino's, and IHG Hotels.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Is Yext pricing per location?$q$, $q$Yes, Yext's published subscription tiers are priced annually per business location managed.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Multi-location listings management$q$, $q$Keep business hours, addresses, and phone numbers accurate across hundreds or thousands of directories and maps.$q$, $q$Franchises and multi-location retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Local SEO and search visibility$q$, $q$Generate and optimize local landing pages to improve rankings in location-based search results.$q$, $q$Enterprise marketing and SEO teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$AI search brand monitoring$q$, $q$Track and improve how a brand is represented in AI assistant and LLM-generated search answers.$q$, $q$Brand and digital visibility teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Emerging$q$, $q$$199 per year per location$q$, $q$annual$q$, NULL, $q$["Distribution to around 30 basic directory sites","Core business listing management","Entry-level visibility features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Essential$q$, $q$$449 per year per location$q$, $q$annual$q$, NULL, $q$["Premium listing management on Google, Apple, Bing, Yahoo, and Yelp","Expanded directory coverage","Improved data accuracy controls"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Complete$q$, $q$$499 per year per location$q$, $q$annual$q$, NULL, $q$["Expanded feature set beyond Essential","Broader listing and reputation coverage","Additional reporting capabilities"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$Premium$q$, $q$$999 per year per location$q$, $q$annual$q$, NULL, $q$["Most comprehensive listing and visibility feature set","Advanced reputation and content distribution tools","Priority access to newer capabilities like AI search monitoring"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$overview$q$, $q$What Is Yext$q$, 2, ARRAY[$q$Yext is a publicly traded enterprise software company, founded in 2006 and headquartered in New York City, listed on the New York Stock Exchange under the ticker YEXT since 2017. It began as a location data and local SEO platform and has since expanded into what it calls an agentic marketing platform.$q$, $q$At its core, Yext helps multi-location brands keep business information such as addresses, hours, and phone numbers accurate and consistent across search engines, maps, directories, and voice assistants, using a centralized Knowledge Graph as the source of truth.$q$, $q$As search behavior shifts toward AI assistants and large language models, Yext has extended its platform to monitor and optimize how brands appear in AI-generated search results, in addition to traditional search and maps visibility.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Knowledge Graph centralizes verified brand data, which feeds Listings Management to syndicate accurate business information across directories and maps, and Reviews to monitor and manage reputation across review platforms.$q$, $q$Pages generates search-optimized local landing pages for individual business locations, while Content Distribution pushes verified content to directories, maps, social platforms, and large language models so AI assistants surface accurate brand information.$q$, $q$Scout is a newer capability focused on real-time monitoring of AI search visibility and competitive intelligence, reflecting Yext's positioning for the rise of AI-driven answer engines alongside traditional search.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e37c82e0-4240-4f11-9aae-4a179e6cd032', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Yext publishes four fixed subscription tiers billed annually per location: Emerging at $199 per year, Essential at $449 per year, Complete at $499 per year, and Premium at $999 per year, with each tier unlocking distribution to more premium listing sites and additional features.$q$, $q$The Emerging plan covers basic listing distribution to roughly 30 directory sites, while Essential and above add management on premium sites such as Google, Apple, Bing, Yahoo, and Yelp.$q$, $q$Because pricing is per location, total cost scales with the number of business locations managed, and mid-market and enterprise buyers typically negotiate custom volume-based pricing rather than paying published rates.$q$]::text[], 2);
